 1	import { SearchInput } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	import { useTranslation } from 'react-i18next';
 4	
 5	type SearchInputProps = {
 6	  pageFlag: number;
 7	  handleNameChange: (searchKeyword: string) => void;
 8	  searchText: string;
 9	};
10	
11	const SearchInputField: React.FC<SearchInputProps> = ({
12	  pageFlag,
13	  handleNameChange,
14	  searchText,
15	}) => {
16	  const { t } = useTranslation('plugin__pipelines-console-plugin');
17	  return (
18	    <SearchInput
19	      value={searchText}
20	      className="pipeline-overview__search-input"
21	      placeholder={
22	        pageFlag === 1
23	          ? t('Search by pipeline name')
24	          : t('Search by repository name')
25	      }
26	      onChange={(event, text) => handleNameChange(text)}
27	      onClear={() => handleNameChange('')}
28	    />
29	  );
30	};
31	
32	export default SearchInputField;

